#include <stdio.h>
#include <stdlib.h>

int max(int a, int b) { return a > b ? a : b; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int* A = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int maxVal = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            int xor = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    xor ^= A[i];
                }
            }
            maxVal = max(maxVal, K ^ xor);
        }
        printf("%d\n", maxVal);
        free(A);
    }
    return 0;

